"use client"

import { logout } from "@/app/actions/logout"

export function LogoutButton() {
  return (
    <button
      onClick={() => logout()}
      className="mt-6 w-full rounded-lg bg-[#184f43] px-4 py-2 text-white font-medium hover:bg-[#133a32] transition-colors"
    >
      Logout
    </button>
  )
}
